import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Yumina Community Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"legal/community-guidelines.md","filePath":"legal/community-guidelines.md","lastUpdated":null}'),n={name:"legal/community-guidelines.md"};function r(l,e,s,c,h,d){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="yumina-community-guidelines" tabindex="-1">Yumina Community Guidelines <a class="header-anchor" href="#yumina-community-guidelines" aria-label="Permalink to &quot;Yumina Community Guidelines&quot;">​</a></h1><p><strong>Last Modified: [EFFECTIVE DATE]</strong></p><h2 id="part-1-introduction" tabindex="-1">Part 1: Introduction <a class="header-anchor" href="#part-1-introduction" aria-label="Permalink to &quot;Part 1: Introduction&quot;">​</a></h2><h3 id="_1-welcome-purpose" tabindex="-1">1. Welcome &amp; Purpose <a class="header-anchor" href="#_1-welcome-purpose" aria-label="Permalink to &quot;1. Welcome &amp; Purpose&quot;">​</a></h3><p>Welcome to Yumina. These Community Guidelines (&quot;Guidelines&quot;) exist to maintain a positive, safe, and creative environment for everyone on our platform. Yumina is an AI interactive fiction and roleplay platform where users create Worlds, chat with AI characters, and collaborate in multiplayer Rooms. That creative freedom comes with shared responsibility.</p><p>These Guidelines apply in addition to the [Yumina Terms of Use]([TERMS OF USE URL]) and [Privacy Policy]([PRIVACY POLICY URL]). Where these documents conflict, the Terms of Use take precedence.</p><p>Yumina is intended for users aged 13 and older. Users under 13 are not permitted to create accounts or use the Service.</p><h3 id="_2-scope" tabindex="-1">2. Scope <a class="header-anchor" href="#_2-scope" aria-label="Permalink to &quot;2. Scope&quot;">​</a></h3><p>These Guidelines apply to all user activity on the Service, including but not limited to:</p><ul><li>World creation and publishing</li><li>Character creation and configuration</li><li>Chat sessions with AI characters</li><li>Multiplayer Rooms (creating, hosting, and participating)</li><li>User profiles, display names, and avatars</li><li>Comments, ratings, and reviews</li><li>Reports and communications with other users or Yumina staff</li></ul><h3 id="_3-rule-updates" tabindex="-1">3. Rule Updates <a class="header-anchor" href="#_3-rule-updates" aria-label="Permalink to &quot;3. Rule Updates&quot;">​</a></h3><p>Yumina may modify these Guidelines at any time. When we make material changes, we will update the &quot;Last Modified&quot; date at the top of this document and, where practical, notify users through the Service. We encourage you to review these Guidelines periodically. Your continued use of the Service after changes are posted constitutes acceptance of the updated Guidelines.</p><hr><h2 id="part-2-content-rating-system" tabindex="-1">Part 2: Content Rating System <a class="header-anchor" href="#part-2-content-rating-system" aria-label="Permalink to &quot;Part 2: Content Rating System&quot;">​</a></h2><p>All User Content published on Yumina must be assigned a content rating by its Creator. Yumina uses a three-tier content rating system. Creators are responsible for selecting the correct rating. Yumina reserves the right to re-rate any content at its sole discretion.</p><h3 id="_4-all-ages-content" tabindex="-1">4. All Ages Content <a class="header-anchor" href="#_4-all-ages-content" aria-label="Permalink to &quot;4. All Ages Content&quot;">​</a></h3><p><strong>Definition:</strong> Content suitable for all users aged 13 and older.</p><p><strong>What is allowed:</strong></p><ul><li>Adventure, mystery, comedy, drama, horror (non-graphic), and other general-audience genres</li><li>Romance, including dating scenarios, emotional intimacy, confessions, hand-holding, kissing, and non-sexual physical affection</li><li>Mild conflict, combat, and action (without graphic depictions of gore or viscera)</li><li>Mild language and humor appropriate for a teen audience</li><li>Fantasy violence (sword fights, magical battles) without graphic injury detail</li></ul><p><strong>What is NOT allowed in All Ages content:</strong></p><ul><li>Sexually explicit or sexually suggestive content, including innuendo intended to arouse</li><li>Graphic depictions of violence, gore, dismemberment, or body horror</li><li>Detailed descriptions of drug use or substance abuse</li><li>Content that would require an R-18 or R-18G rating under these Guidelines</li></ul><h3 id="_5-r-18-content" tabindex="-1">5. R-18 Content <a class="header-anchor" href="#_5-r-18-content" aria-label="Permalink to &quot;5. R-18 Content&quot;">​</a></h3><p><strong>Definition:</strong> Content that is sexually explicit, sexually suggestive, or contains mature adult themes unsuitable for users under 18.</p><p><strong>What qualifies as R-18:</strong></p><ul><li>Sexually explicit scenes, descriptions, or dialogue</li><li>Nudity depicted in a sexual context</li><li>Sexual innuendo, fetish content, or sexually suggestive scenarios</li><li>Mature themes such as graphic drug use, intense psychological horror, or extreme profanity used pervasively</li><li>Content that, while not depicting gore, is clearly intended for an adult audience</li></ul><p><strong>Access requirements:</strong></p><ul><li>Users must be 18 years of age or older</li><li>Users must have declared their birth year in their account settings, confirming they are 18+</li><li>Users must have set their content level to R-18 or R-18G in their account settings</li><li>R-18 content is hidden from all users who have not met all three requirements</li></ul><h3 id="_6-r-18g-content" tabindex="-1">6. R-18G Content <a class="header-anchor" href="#_6-r-18g-content" aria-label="Permalink to &quot;6. R-18G Content&quot;">​</a></h3><p><strong>Definition:</strong> Content depicting grotesque imagery, gore, or scenes designed to cause physical discomfort or disgust.</p><p><strong>What qualifies as R-18G:</strong></p><ul><li>Graphic depictions of dismemberment, mutilation, or amputation</li><li>Viscera, exposed organs, or detailed internal body imagery</li><li>Body horror (unnatural bodily transformation, parasitic infestation, flesh corruption)</li><li>Cannibalism depicted in graphic detail</li><li>Graphic depictions of bodily fluids in disturbing or revolting contexts</li><li>Torture depicted with graphic physical detail</li><li>Content combining extreme gore with sexual elements</li></ul><p><strong>What does NOT qualify as R-18G:</strong></p><ul><li>Heroic sacrifice or dramatic death scenes without gratuitous anatomical detail</li><li>Narrative or dramatic death (a character dying in a story-appropriate way)</li><li>Bittersweet or tragic endings</li><li>Blood mentioned in passing without graphic elaboration</li><li>Fantasy combat injuries described briefly</li></ul><p><strong>Access requirements:</strong></p><ul><li>Users must be 18 years of age or older</li><li>Users must have declared their birth year in their account settings, confirming they are 18+</li><li>Users must have set their content level to R-18G in their account settings</li><li>R-18G content is hidden from all users who have not met all three requirements</li></ul><h3 id="_7-content-rating-obligations" tabindex="-1">7. Content Rating Obligations <a class="header-anchor" href="#_7-content-rating-obligations" aria-label="Permalink to &quot;7. Content Rating Obligations&quot;">​</a></h3><ul><li>Creators MUST select the appropriate content rating for every World, character, or piece of content they publish</li><li>When in doubt, rate conservatively (choose the higher rating)</li><li>If your content contains elements from multiple rating tiers, apply the highest applicable rating</li><li>Yumina reserves the right to review and re-rate any content at any time</li><li>If Yumina re-rates your content, you will be notified of the change and the reason</li></ul><h3 id="_8-misrating-penalties" tabindex="-1">8. Misrating Penalties <a class="header-anchor" href="#_8-misrating-penalties" aria-label="Permalink to &quot;8. Misrating Penalties&quot;">​</a></h3><p>Deliberately marking R-18 or R-18G content with a lower rating (for example, labeling sexually explicit content as &quot;All Ages&quot;) is a serious violation. This undermines the safety of younger users and the trust of the community.</p><p><strong>Penalty escalation for deliberate misrating:</strong></p><ol><li><strong>First offense:</strong> Warning issued, content re-rated by Yumina</li><li><strong>Second offense:</strong> Publishing privileges restricted (temporary or indefinite)</li><li><strong>Third offense:</strong> Temporary account ban</li><li><strong>Continued or egregious violations:</strong> Permanent account ban</li></ol><p>Yumina distinguishes between honest mistakes and deliberate misrating. If you accidentally select the wrong rating and correct it promptly (or cooperate when notified), this will be treated differently from intentional abuse.</p><hr><h2 id="part-3-absolute-prohibitions-zero-tolerance" tabindex="-1">Part 3: Absolute Prohibitions (Zero Tolerance) <a class="header-anchor" href="#part-3-absolute-prohibitions-zero-tolerance" aria-label="Permalink to &quot;Part 3: Absolute Prohibitions (Zero Tolerance)&quot;">​</a></h2><p>The following categories of content and conduct result in an immediate permanent ban from Yumina, with no prior warnings. Yumina may also refer violations to law enforcement where applicable.</p><h3 id="_9-minor-safety-real-child-images" tabindex="-1">9. Minor Safety &amp; Real Child Images <a class="header-anchor" href="#_9-minor-safety-real-child-images" aria-label="Permalink to &quot;9. Minor Safety &amp; Real Child Images&quot;">​</a></h3><p>Yumina has an absolute zero-tolerance policy regarding the sexualization of minors and the use of real child images.</p><p>The following are strictly prohibited:</p><ul><li>Any sexual or sexually suggestive content depicting, describing, or involving minors (persons under 18)</li><li>Sexual content involving characters who are canonically minors, even if the content describes them as &quot;aged up&quot; to 18 or older</li><li>Sexual content involving characters whose age is ambiguous and who could reasonably be interpreted as minors. Indicators of minor status include but are not limited to: stated age under 18, school uniforms or school settings, descriptions such as &quot;looks young,&quot; &quot;childlike,&quot; or &quot;petite&quot; when combined with sexual context, or visual depictions with childlike proportions</li><li>Child Sexual Abuse Material (CSAM) of any kind, including AI-generated CSAM</li><li>Real photographs or realistic depictions of actual children used in any context on Yumina, including character avatars, World assets, backgrounds, profile pictures, or any content where the image represents a character in a roleplay or interactive fiction context. This prohibition applies regardless of whether the content is sexual in nature — the use of real child images on a roleplay platform creates inherent risk and is not permitted.</li></ul><p><strong>Enforcement:</strong></p><ul><li>Violations result in immediate and permanent account termination</li><li>CSAM and suspected child exploitation will be reported to the National Center for Missing &amp; Exploited Children (NCMEC) and/or relevant law enforcement agencies immediately</li><li>Yumina will cooperate fully with law enforcement investigations related to child safety</li></ul><h3 id="_10-human-trafficking-sexual-exploitation" tabindex="-1">10. Human Trafficking &amp; Sexual Exploitation <a class="header-anchor" href="#_10-human-trafficking-sexual-exploitation" aria-label="Permalink to &quot;10. Human Trafficking &amp; Sexual Exploitation&quot;">​</a></h3><p>Content that promotes, facilitates, glorifies, or provides instructions for human trafficking or the sexual exploitation of any person is strictly prohibited. This includes:</p><ul><li>Recruitment, transportation, or harboring of persons for exploitation</li><li>Commercial sexual exploitation</li><li>Forced labor or servitude</li><li>Content designed to normalize or trivialize trafficking or exploitation</li></ul><p>Violations result in immediate permanent ban and may be referred to law enforcement.</p><hr><h2 id="part-4-real-people-public-figures" tabindex="-1">Part 4: Real People &amp; Public Figures <a class="header-anchor" href="#part-4-real-people-public-figures" aria-label="Permalink to &quot;Part 4: Real People &amp; Public Figures&quot;">​</a></h2><h3 id="_11-real-person-characters" tabindex="-1">11. Real Person Characters <a class="header-anchor" href="#_11-real-person-characters" aria-label="Permalink to &quot;11. Real Person Characters&quot;">​</a></h3><p>Creating characters based on real, identifiable people is subject to the following rules:</p><ul><li><strong>Authorization required:</strong> Using a real person&#39;s name, likeness, voice, or other identifying characteristics for a character requires that you hold the appropriate copyright, trademark, or personal authorization to do so</li><li><strong>Fictional labeling:</strong> All characters based on real people must be clearly labeled as fictional (e.g., in the World description or character bio)</li><li><strong>R-18 and R-18G content featuring real people is strictly prohibited</strong>, even if the Creator claims to have authorization from the person depicted. No exceptions.</li><li>Yumina is not responsible for verifying authorization claims and may remove content at its discretion if a valid complaint is received</li></ul><h3 id="_12-deepfake-ai-generated-real-person-content" tabindex="-1">12. Deepfake &amp; AI-Generated Real Person Content <a class="header-anchor" href="#_12-deepfake-ai-generated-real-person-content" aria-label="Permalink to &quot;12. Deepfake &amp; AI-Generated Real Person Content&quot;">​</a></h3><ul><li>AI-generated NSFW (sexually explicit or suggestive) images depicting real, identifiable people are strictly prohibited. This constitutes deepfake content and is banned regardless of context.</li><li>AI-generated images that could reasonably be mistaken for real photographs of identifiable individuals are prohibited in any NSFW or R-18/R-18G context.</li><li>This rule applies to all AI image generation tools, whether integrated into Yumina or used externally and uploaded to the Service.</li></ul><h3 id="_13-political-figures" tabindex="-1">13. Political Figures <a class="header-anchor" href="#_13-political-figures" aria-label="Permalink to &quot;13. Political Figures&quot;">​</a></h3><ul><li>Characters based on real political figures (current or historical) are allowed for the purposes of <strong>education, historical commentary, parody, and satire</strong>, in <strong>All Ages content only</strong></li><li>R-18 or R-18G content featuring real political figures is strictly prohibited</li><li>Content must be clearly presented as fictional, satirical, or parodic</li><li>No content featuring political figures that constitutes political misinformation likely to cause real-world harm, incite violence, or interfere with political processes (such as elections)</li></ul><hr><h2 id="part-5-prohibited-conduct" tabindex="-1">Part 5: Prohibited Conduct <a class="header-anchor" href="#part-5-prohibited-conduct" aria-label="Permalink to &quot;Part 5: Prohibited Conduct&quot;">​</a></h2><h3 id="_14-illegal-activities" tabindex="-1">14. Illegal Activities <a class="header-anchor" href="#_14-illegal-activities" aria-label="Permalink to &quot;14. Illegal Activities&quot;">​</a></h3><p>Do not use the Service to engage in, promote, facilitate, or provide instructions for illegal activities. This includes but is not limited to:</p><ul><li>Drug trafficking or manufacturing</li><li>Weapons trafficking</li><li>Fraud, identity theft, or financial crimes</li><li>Hacking, unauthorized access to computer systems, or distribution of exploits</li><li>Any activity that violates applicable local, national, or international law</li></ul><p>Content that depicts illegal activities in a fictional or educational context (e.g., a crime drama World) is generally permitted, provided it does not serve as a practical guide or instruction manual for committing real crimes.</p><h3 id="_15-hate-speech" tabindex="-1">15. Hate Speech <a class="header-anchor" href="#_15-hate-speech" aria-label="Permalink to &quot;15. Hate Speech&quot;">​</a></h3><p>Content that promotes hatred, discrimination, or violence against individuals or groups based on the following protected characteristics is prohibited:</p><ul><li>Race or ethnicity</li><li>Nationality or national origin</li><li>Religion or religious belief</li><li>Disability (physical or mental)</li><li>Gender or sex</li><li>Age</li><li>Veteran status</li><li>Sexual orientation</li><li>Gender identity or expression</li></ul><p>This includes:</p><ul><li>Slurs, dehumanizing language, or derogatory stereotypes directed at protected groups</li><li>Glorification of historical atrocities, genocide, or ethnic cleansing</li><li>Calls for violence, exclusion, or discrimination against protected groups</li><li>Propaganda for hate groups or extremist ideologies</li><li>Content designed to recruit for hate movements</li></ul><p>Fictional works that depict prejudice or discrimination as part of a narrative (e.g., a story exploring themes of overcoming bigotry) are permitted, provided the content does not itself advocate for or glorify such views.</p><h3 id="_16-misinformation" tabindex="-1">16. Misinformation <a class="header-anchor" href="#_16-misinformation" aria-label="Permalink to &quot;16. Misinformation&quot;">​</a></h3><p>The following types of misinformation are prohibited:</p><ul><li>False information that is likely to incite or contribute to real-world violence</li><li>False information designed to interfere with political processes, including elections, referendums, or civic participation</li><li>Fabricated claims presented as fact that pose a credible risk of real-world harm</li></ul><p>Fictional content, satire, and speculative fiction are not misinformation, provided they are clearly presented as fictional.</p><h3 id="_17-harassment-bullying" tabindex="-1">17. Harassment &amp; Bullying <a class="header-anchor" href="#_17-harassment-bullying" aria-label="Permalink to &quot;17. Harassment &amp; Bullying&quot;">​</a></h3><p>Yumina is committed to a community free from harassment. The following are prohibited:</p><ul><li>Aggressive, targeted insults or personal attacks against other users</li><li>Threats of any kind, including threats of violence, threats to expose personal information, or threats to damage reputation</li><li>Stalking, including persistent unwanted contact, monitoring, or following a user across the platform after being asked to stop</li><li>Doxxing (publishing another person&#39;s private information without their consent)</li><li>Repeated unwanted contact after a user has indicated they do not wish to communicate</li><li>Coordinated harassment campaigns against individuals or groups</li><li>Derogatory, demeaning, or humiliating comments directed at specific users</li><li>Bullying, including sustained patterns of behavior intended to intimidate, belittle, or exclude</li></ul><p>If you are being harassed, report the behavior immediately using the reporting tools described in Section 39 of these Guidelines.</p><h3 id="_18-violence-threats" tabindex="-1">18. Violence &amp; Threats <a class="header-anchor" href="#_18-violence-threats" aria-label="Permalink to &quot;18. Violence &amp; Threats&quot;">​</a></h3><ul><li>Threats of real-world violence against any person, group, or institution are strictly prohibited and may result in immediate permanent ban and referral to law enforcement</li><li>Content that promotes, encourages, or provides instructions for committing real-world violence is prohibited</li><li>Graphic, gratuitous depictions of real-world violence intended to shock, glorify, or promote violence are prohibited</li></ul><p>Fictional violence in the context of interactive fiction and roleplay (combat scenes, conflict, dramatic tension) is permitted within the appropriate content rating tier.</p><h3 id="_19-self-harm-content" tabindex="-1">19. Self-Harm Content <a class="header-anchor" href="#_19-self-harm-content" aria-label="Permalink to &quot;19. Self-Harm Content&quot;">​</a></h3><p>The following are prohibited:</p><ul><li>Content that promotes, encourages, glorifies, or provides instructions for suicide</li><li>Content that promotes, encourages, or provides instructions for self-mutilation or self-injury</li><li>Content that promotes or glorifies eating disorders or dangerous dietary practices</li><li>Content that promotes or glorifies substance abuse or addiction</li></ul><p>Fictional works that address these topics in a thoughtful, narrative context (e.g., a character struggling with and seeking help for mental health issues) are permitted, provided the content does not serve as promotion or instruction.</p><p>If you or someone you know is in crisis, please contact a crisis helpline in your area:</p><ul><li><strong>United States:</strong> Call or text 988 (Suicide &amp; Crisis Lifeline)</li><li><strong>United Kingdom:</strong> 116 123 (Samaritans)</li><li><strong>Japan:</strong> 0570-064-556 (いのちの電話)</li><li><strong>International directory:</strong> <a href="https://findahelpline.com" target="_blank" rel="noreferrer">findahelpline.com</a></li></ul><h3 id="_20-personal-confidential-information" tabindex="-1">20. Personal &amp; Confidential Information <a class="header-anchor" href="#_20-personal-confidential-information" aria-label="Permalink to &quot;20. Personal &amp; Confidential Information&quot;">​</a></h3><p>Do not share another person&#39;s private or confidential information on the Service without their explicit consent. This includes:</p><ul><li>Real names (when shared against the person&#39;s wishes)</li><li>Home or work addresses</li><li>Phone numbers</li><li>Email addresses</li><li>Financial information (bank accounts, credit card numbers)</li><li>Government-issued identification numbers</li><li>Private photographs or videos</li><li>Medical or health information</li><li>Any other information that could be used to identify or locate a person against their will</li></ul><h3 id="_21-impersonation-deception" tabindex="-1">21. Impersonation &amp; Deception <a class="header-anchor" href="#_21-impersonation-deception" aria-label="Permalink to &quot;21. Impersonation &amp; Deception&quot;">​</a></h3><ul><li>Do not impersonate other users, Yumina staff, moderators, or administrators</li><li>Do not create accounts designed to mislead others about your identity or affiliation</li><li>Do not falsely claim to represent Yumina or to have authority you do not possess</li><li>Do not use misleading display names, avatars, or profile information to deceive other users about who you are</li></ul><h3 id="_22-spam-manipulation" tabindex="-1">22. Spam &amp; Manipulation <a class="header-anchor" href="#_22-spam-manipulation" aria-label="Permalink to &quot;22. Spam &amp; Manipulation&quot;">​</a></h3><ul><li>Do not send spam, including mass unsolicited messages, advertisements, or promotional content</li><li>Do not use bots, scripts, or automated tools to artificially inflate engagement metrics (downloads, favorites, ratings)</li><li>Do not engage in mass solicitation or chain messaging</li><li>Do not post unauthorized advertisements or commercial solicitations</li><li>Do not engage in review manipulation, vote brigading, or coordinated inauthentic behavior</li></ul><h3 id="_23-malicious-software" tabindex="-1">23. Malicious Software <a class="header-anchor" href="#_23-malicious-software" aria-label="Permalink to &quot;23. Malicious Software&quot;">​</a></h3><ul><li>Do not upload, distribute, or link to viruses, malware, ransomware, spyware, trojans, or any other destructive or malicious code</li><li>Do not attempt to exploit vulnerabilities in the Service</li><li>Do not attempt to compromise the security or integrity of the Service or its users&#39; data</li></ul><p>If you discover a security vulnerability, please report it responsibly to [SECURITY EMAIL].</p><h3 id="_24-intellectual-property" tabindex="-1">24. Intellectual Property <a class="header-anchor" href="#_24-intellectual-property" aria-label="Permalink to &quot;24. Intellectual Property&quot;">​</a></h3><ul><li>Respect the copyrights, trademarks, and other intellectual property rights of others</li><li>Do not upload or publish content that infringes on another party&#39;s intellectual property without appropriate rights or authorization</li><li>Honor the re-edit and export permission settings that Creators have configured for their Worlds. If a Creator has disabled re-editing or exporting, respect that decision.</li><li>Accounts that consist solely or primarily of content copied from other Creators without permission or attribution may be disabled</li><li>If you believe your intellectual property has been infringed, follow the process outlined in the [Terms of Use]([TERMS OF USE URL])</li></ul><h3 id="_25-bestiality" tabindex="-1">25. Bestiality <a class="header-anchor" href="#_25-bestiality" aria-label="Permalink to &quot;25. Bestiality&quot;">​</a></h3><ul><li>Content that promotes, normalizes, or depicts sexual activity with real animals is prohibited</li><li>This includes realistic depictions of sexual acts involving real animal species</li><li>Fictional, fantastical, or mythological species (e.g., dragons, werewolves, elves, aliens, and other non-real creatures) are exempt from this rule, provided the content is appropriately rated under the content rating system. This exemption applies to species that <strong>do not exist in the real world</strong> and are clearly presented as fictional or fantastical. Characters that are realistic depictions of real animal species with only minor fictional modifications (e.g., a real dog breed that can speak) do not qualify for this exemption</li></ul><h3 id="_26-non-consensual-intimate-imagery-ncii" tabindex="-1">26. Non-Consensual Intimate Imagery (NCII) <a class="header-anchor" href="#_26-non-consensual-intimate-imagery-ncii" aria-label="Permalink to &quot;26. Non-Consensual Intimate Imagery (NCII)&quot;">​</a></h3><p>Sharing, uploading, or distributing intimate or sexually explicit images of any real person without their consent is strictly prohibited, whether the images are real photographs, AI-generated, or digitally manipulated. This includes:</p><ul><li>Revenge pornography or intimate images shared without the depicted person&#39;s consent</li><li>AI-generated intimate imagery of real, identifiable persons (see also Section 12)</li><li>Threats to distribute intimate imagery as a means of coercion or harassment</li></ul><p>Violations may result in immediate permanent ban and referral to law enforcement where applicable.</p><h3 id="_27-financial-scams-unauthorized-solicitation" tabindex="-1">27. Financial Scams &amp; Unauthorized Solicitation <a class="header-anchor" href="#_27-financial-scams-unauthorized-solicitation" aria-label="Permalink to &quot;27. Financial Scams &amp; Unauthorized Solicitation&quot;">​</a></h3><p>Using the Service to promote, facilitate, or engage in financial fraud is prohibited. This includes:</p><ul><li>Pyramid schemes, Ponzi schemes, or multi-level marketing solicitations</li><li>Cryptocurrency fraud, pump-and-dump schemes, or unauthorized investment solicitations</li><li>Phishing attempts or impersonation for financial gain</li><li>Using World content, chat sessions, or multiplayer Rooms to solicit money from users outside of Yumina&#39;s official payment and tipping systems</li></ul><h3 id="_28-account-abuse" tabindex="-1">28. Account Abuse <a class="header-anchor" href="#_28-account-abuse" aria-label="Permalink to &quot;28. Account Abuse&quot;">​</a></h3><ul><li>Do not hijack, compromise, or gain unauthorized access to another user&#39;s account</li><li>Do not access another user&#39;s account without their explicit permission</li><li>Do not create multiple accounts to evade bans, circumvent restrictions, or manipulate the platform</li><li>Do not sell, purchase, trade, or transfer accounts</li><li>Do not share account credentials with others</li></ul><hr><h2 id="part-6-ai-generated-content-rules" tabindex="-1">Part 6: AI-Generated Content Rules <a class="header-anchor" href="#part-6-ai-generated-content-rules" aria-label="Permalink to &quot;Part 6: AI-Generated Content Rules&quot;">​</a></h2><p>Yumina is an AI-powered platform. The following rules govern the relationship between users and AI-generated content.</p><h3 id="_29-user-responsibility-for-prompts" tabindex="-1">29. User Responsibility for Prompts <a class="header-anchor" href="#_29-user-responsibility-for-prompts" aria-label="Permalink to &quot;29. User Responsibility for Prompts&quot;">​</a></h3><p>You are responsible for the prompts you write and the content you actively guide the AI to generate. If you craft prompts, character instructions, system directives, or World configurations that are designed to produce content that violates these Guidelines, you are responsible for the resulting output.</p><p>This includes:</p><ul><li>Writing prompts that explicitly request prohibited content</li><li>Configuring characters or Worlds to systematically produce violating content</li><li>Using jailbreak techniques, prompt injection, or other methods to coerce the AI into generating prohibited content</li></ul><h3 id="_30-unintentional-ai-output" tabindex="-1">30. Unintentional AI Output <a class="header-anchor" href="#_30-unintentional-ai-output" aria-label="Permalink to &quot;30. Unintentional AI Output&quot;">​</a></h3><p>AI language models may occasionally generate content that violates these Guidelines without any intent or prompting from the user. If this occurs:</p><ul><li>You are not held responsible for genuinely unintentional AI output</li><li>You should report the incident so that Yumina can review and adjust content filters</li><li>Do not publish, share, or redistribute AI-generated content that you know violates these Guidelines, even if you did not prompt it</li><li>If you become aware that AI-generated content in your published World violates these Guidelines, you are expected to remove or report it promptly. Knowingly allowing violating content to remain in a published World may be treated as a violation</li></ul><h3 id="_31-content-filter-circumvention" tabindex="-1">31. Content Filter Circumvention <a class="header-anchor" href="#_31-content-filter-circumvention" aria-label="Permalink to &quot;31. Content Filter Circumvention&quot;">​</a></h3><p>Deliberately attempting to bypass, circumvent, or disable Yumina&#39;s content filters, safety systems, or moderation tools is a violation of these Guidelines. This includes:</p><ul><li>Prompt injection attacks designed to override system instructions</li><li>Techniques intended to &quot;jailbreak&quot; the AI into ignoring safety guidelines</li><li>Encoding, obfuscating, or otherwise disguising prohibited prompts to evade detection</li><li>Sharing methods or tools for circumventing content filters with other users</li></ul><h3 id="_32-ai-content-equals-user-content" tabindex="-1">32. AI Content Equals User Content <a class="header-anchor" href="#_32-ai-content-equals-user-content" aria-label="Permalink to &quot;32. AI Content Equals User Content&quot;">​</a></h3><p>All content generated by AI on the Service is subject to these Community Guidelines in the same way as content written directly by a user. There is no distinction in enforcement between:</p><ul><li>Text you type directly</li><li>Text generated by AI in response to your prompts</li><li>Images generated by AI tools</li><li>Any other AI-generated output within the Service</li></ul><p>If AI-generated content in your World, character, or chat session violates these Guidelines, the same enforcement actions apply as if you had written the content yourself (subject to the unintentional output exception in Section 30).</p><hr><h2 id="part-7-multiplayer-room-rules" tabindex="-1">Part 7: Multiplayer Room Rules <a class="header-anchor" href="#part-7-multiplayer-room-rules" aria-label="Permalink to &quot;Part 7: Multiplayer Room Rules&quot;">​</a></h2><p>Multiplayer Rooms allow multiple users to participate in shared interactive fiction sessions. Because Rooms involve real-time interaction between users, additional rules apply.</p><h3 id="_33-room-content-rating" tabindex="-1">33. Room Content Rating <a class="header-anchor" href="#_33-room-content-rating" aria-label="Permalink to &quot;33. Room Content Rating&quot;">​</a></h3><ul><li>The Room creator MUST set a content rating (All Ages, R-18, or R-18G) at the time of Room creation</li><li>The Room&#39;s content rating is displayed prominently in the Room listing and lobby</li><li>All content within a Room — including user messages, AI-generated content, character actions, and shared media — must not exceed the Room&#39;s set content rating</li><li>Posting content that exceeds the Room&#39;s rating is a violation of these Guidelines, enforceable against the user who posted it</li></ul><h3 id="_34-joining-r-18-r-18g-rooms" tabindex="-1">34. Joining R-18 / R-18G Rooms <a class="header-anchor" href="#_34-joining-r-18-r-18g-rooms" aria-label="Permalink to &quot;34. Joining R-18 / R-18G Rooms&quot;">​</a></h3><p>When a user attempts to join a Room rated R-18 or R-18G, the following confirmation process applies:</p><ul><li>A confirmation popup is displayed showing the Room&#39;s content rating</li><li>The user must confirm that they are 18 years of age or older</li><li>The user must confirm that they understand and consent to potentially encountering content at the Room&#39;s rated level</li><li>The user must have their content level set to a level that includes the Room&#39;s rating (e.g., R-18 or R-18G for R-18 Rooms; R-18G for R-18G Rooms)</li><li>Users who do not meet all requirements cannot join the Room</li></ul><h3 id="_35-room-host-responsibilities" tabindex="-1">35. Room Host Responsibilities <a class="header-anchor" href="#_35-room-host-responsibilities" aria-label="Permalink to &quot;35. Room Host Responsibilities&quot;">​</a></h3><p>The Room creator (host) has additional responsibilities:</p><ul><li><strong>Maintain order:</strong> Ensure participants follow the Room&#39;s content rating and these Guidelines</li><li><strong>Moderate content:</strong> Address violations promptly by warning, muting, kicking, or banning users who violate rules</li><li><strong>Kick and ban:</strong> Hosts have the authority to remove users from their Room at their discretion</li><li><strong>Report:</strong> Hosts should report serious violations to Yumina through the standard reporting process</li></ul><p>Hosts who persistently fail to moderate their Rooms — allowing ongoing violations to continue unchecked — may lose the ability to create or host Rooms.</p><h3 id="_36-participant-rights" tabindex="-1">36. Participant Rights <a class="header-anchor" href="#_36-participant-rights" aria-label="Permalink to &quot;36. Participant Rights&quot;">​</a></h3><p>All Room participants have the following rights:</p><ul><li><strong>Report:</strong> Any participant can report content or other users within a Room at any time</li><li><strong>Leave:</strong> Any participant can leave a Room at any time, for any reason, without penalty</li><li><strong>Block:</strong> Any participant can block other users, which prevents further interaction</li></ul><h3 id="_37-r-18-interaction-consent" tabindex="-1">37. R-18 Interaction Consent <a class="header-anchor" href="#_37-r-18-interaction-consent" aria-label="Permalink to &quot;37. R-18 Interaction Consent&quot;">​</a></h3><ul><li>All participants in R-18 or R-18G Rooms must have their content level set to the appropriate level in their account settings</li><li>Consent to participate in mature content is ongoing and can be withdrawn at any time by leaving the Room</li><li>No participant may pressure, coerce, or shame another participant into remaining in a Room or engaging with content they are uncomfortable with</li><li>If a participant expresses discomfort with the direction of content, other participants and the host should respect that</li></ul><h3 id="_38-rating-change-prohibition" tabindex="-1">38. Rating Change Prohibition <a class="header-anchor" href="#_38-rating-change-prohibition" aria-label="Permalink to &quot;38. Rating Change Prohibition&quot;">​</a></h3><ul><li>A Room&#39;s content rating CANNOT be upgraded during an active session (for example, changing an All Ages Room to R-18 while users are present)</li><li>If participants wish to engage in content at a higher rating level, a new Room must be created with the appropriate rating</li><li>This rule exists to protect participants who joined under the expectation of a specific content level</li></ul><hr><h2 id="part-8-reporting-enforcement" tabindex="-1">Part 8: Reporting &amp; Enforcement <a class="header-anchor" href="#part-8-reporting-enforcement" aria-label="Permalink to &quot;Part 8: Reporting &amp; Enforcement&quot;">​</a></h2><h3 id="_39-how-to-report" tabindex="-1">39. How to Report <a class="header-anchor" href="#_39-how-to-report" aria-label="Permalink to &quot;39. How to Report&quot;">​</a></h3><p>If you encounter content or behavior that violates these Guidelines, you can report it through the following channels:</p><ul><li><strong>In-platform reporting:</strong> Use the report button available on Worlds, characters, chat messages, Room content, and user profiles</li><li><strong>Email:</strong> Send a report to [CONTACT EMAIL]</li></ul><p>All reports are reviewed by the Yumina team. Reports are confidential — the identity of the reporter is not disclosed to the reported party.</p><h3 id="_40-what-to-include-in-reports" tabindex="-1">40. What to Include in Reports <a class="header-anchor" href="#_40-what-to-include-in-reports" aria-label="Permalink to &quot;40. What to Include in Reports&quot;">​</a></h3><p>To help us review your report efficiently, please include:</p><ul><li><strong>Location:</strong> Where the violating content is located (World name/URL, Room name, user profile, specific message)</li><li><strong>Rule violated:</strong> Which section of these Guidelines you believe was violated</li><li><strong>Context:</strong> Any additional context, screenshots, or evidence that would help us understand the situation</li><li><strong>Urgency:</strong> If the situation involves immediate danger (threats of violence, CSAM, etc.), please indicate this clearly</li></ul><h3 id="_41-review-process" tabindex="-1">41. Review Process <a class="header-anchor" href="#_41-review-process" aria-label="Permalink to &quot;41. Review Process&quot;">​</a></h3><p>When Yumina receives a report:</p><ol><li>The report is reviewed by the Yumina moderation team</li><li>The reported content or behavior is evaluated against these Guidelines</li><li>If a violation is confirmed, appropriate action is taken (see Section 42)</li><li>Both the reporter and the reported party are notified of the outcome, including what action was taken and why</li><li>If no violation is found, the reporter is notified that the report was reviewed and no action was warranted</li></ol><p>Review times vary depending on report volume and complexity. Urgent reports (safety threats, CSAM) are prioritized.</p><h3 id="_42-penalty-ladder" tabindex="-1">42. Penalty Ladder <a class="header-anchor" href="#_42-penalty-ladder" aria-label="Permalink to &quot;42. Penalty Ladder&quot;">​</a></h3><p>For most violations, Yumina follows an escalating penalty structure:</p><ol><li><strong>Warning</strong> — A formal notice that a violation occurred, with an explanation of the rule and expected behavior</li><li><strong>Content removal</strong> — The violating content is removed or hidden from the platform</li><li><strong>Feature restriction</strong> — Specific privileges are restricted (e.g., publishing ban, Room creation ban, commenting ban) for a defined period or until conditions are met</li><li><strong>Temporary ban (7 days)</strong> — Account access is suspended for 7 days</li><li><strong>Temporary ban (30 days)</strong> — Account access is suspended for 30 days</li><li><strong>Permanent ban</strong> — Account is permanently terminated with no possibility of reinstatement (except through a successful appeal)</li></ol><p>The severity of enforcement depends on:</p><ul><li>The nature and severity of the violation</li><li>Whether the violation was intentional or accidental</li><li>The user&#39;s prior history of violations</li><li>The potential harm caused by the violation</li></ul><p>Yumina reserves the right to skip steps in the penalty ladder for serious violations.</p><h3 id="_43-immediate-permanent-ban" tabindex="-1">43. Immediate Permanent Ban <a class="header-anchor" href="#_43-immediate-permanent-ban" aria-label="Permalink to &quot;43. Immediate Permanent Ban&quot;">​</a></h3><p>The following violations result in immediate permanent account termination without prior warnings:</p><ul><li>Child Sexual Abuse Material (CSAM) or any sexual content involving minors</li><li>Credible threats of real-world violence</li><li>Human trafficking or sexual exploitation content</li><li>Sexual exploitation of minors in any form</li></ul><p>These violations may also be referred to law enforcement agencies.</p><h3 id="_44-appeal-process" tabindex="-1">44. Appeal Process <a class="header-anchor" href="#_44-appeal-process" aria-label="Permalink to &quot;44. Appeal Process&quot;">​</a></h3><p>If you believe an enforcement action was taken in error, you may appeal:</p><ul><li><strong>How to appeal:</strong> Send an email to [CONTACT EMAIL] with the subject line &quot;Appeal&quot; and include your username, the action taken, and your explanation of why you believe the action was incorrect</li><li><strong>Response time:</strong> Yumina will respond to appeals within 14 business days</li><li><strong>Penalty during appeal:</strong> Penalties are NOT suspended during the appeal process. The enforcement action remains in effect until the appeal is resolved.</li><li><strong>Final decision:</strong> The decision made after an appeal review is final</li></ul><h3 id="_45-false-reports" tabindex="-1">45. False Reports <a class="header-anchor" href="#_45-false-reports" aria-label="Permalink to &quot;45. False Reports&quot;">​</a></h3><p>The reporting system exists to keep the community safe. Abuse of the reporting system undermines that purpose.</p><ul><li>Submitting malicious, knowingly false, or frivolous reports is a violation of these Guidelines</li><li>Repeatedly filing false reports against a specific user constitutes harassment</li><li>Users who abuse the reporting system will be subject to the same penalty ladder described in Section 42</li></ul><hr><h2 id="part-9-closing" tabindex="-1">Part 9: Closing <a class="header-anchor" href="#part-9-closing" aria-label="Permalink to &quot;Part 9: Closing&quot;">​</a></h2><h3 id="_46-cooperation-with-law-enforcement" tabindex="-1">46. Cooperation with Law Enforcement <a class="header-anchor" href="#_46-cooperation-with-law-enforcement" aria-label="Permalink to &quot;46. Cooperation with Law Enforcement&quot;">​</a></h3><p>Yumina will cooperate with law enforcement agencies when legally required to do so, including in response to valid legal process such as subpoenas, court orders, or search warrants. Yumina may also voluntarily report to law enforcement when we have a good-faith belief that content or conduct on the Service involves imminent danger to life, child exploitation, or other serious criminal activity.</p><h3 id="_47-contact" tabindex="-1">47. Contact <a class="header-anchor" href="#_47-contact" aria-label="Permalink to &quot;47. Contact&quot;">​</a></h3><p>If you have questions about these Community Guidelines, need to report a violation, or wish to appeal an enforcement action, please contact us:</p><ul><li><strong>Email:</strong> [CONTACT EMAIL]</li><li><strong>Security issues:</strong> [SECURITY EMAIL]</li></ul><p>Thank you for being part of the Yumina community. These Guidelines exist because we believe that creative freedom and user safety are not at odds — they depend on each other. By following these rules, you help build a platform where everyone can create, explore, and play with confidence.</p><hr><h2 id="placeholders-to-complete" tabindex="-1">Placeholders to Complete <a class="header-anchor" href="#placeholders-to-complete" aria-label="Permalink to &quot;Placeholders to Complete&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>[EFFECTIVE DATE]</code></td><td>The date these Guidelines take effect</td></tr><tr><td><code>[TERMS OF USE URL]</code></td><td>URL to the Yumina Terms of Use</td></tr><tr><td><code>[PRIVACY POLICY URL]</code></td><td>URL to the Yumina Privacy Policy</td></tr><tr><td><code>[CONTACT EMAIL]</code></td><td>General contact / reporting email address</td></tr><tr><td><code>[SECURITY EMAIL]</code></td><td>Security vulnerability reporting email address</td></tr></tbody></table>',192)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
